from agent import *from models.products import *DUPE_PRODS = []XCAT = ['Sale', 'NEUHEITEN', 'Bestseller', 'Neuheiten', 'BESTSELLER']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.queue(Request('https://shop4runners.com'), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//div[@x-ref="nav-mobile"]//div[contains(@class, "navigation--level-top")]')    for cat in cats:        name = cat.xpath('a/div/text()').string()        cats1 = cat.xpath('template/div[contains(@class, "nav__level-1")]/div[contains(@class, "category-item")]')        for cat1 in cats1:            name1 = cat1.xpath('div[contains(@class, "nav-item--and-text")]/div/a[contains(@class, "title")]/text()').string()            if name1 not in XCAT:                cats2 = cat1.xpath('div/div/div[contains(@class, "nav__column")]/div[contains(@class, "category-item")] | .//div[contains(@class, "nav__column")]/div[contains(@class, "navigation__container")]/div[contains(@class, "nav__column")]/div')                for cat2 in cats2:                    name2 = cat2.xpath('div[contains(@class, "nav-item--category")]/a/text() | div[contains(@class, "nav-item--and-text")]/div/a[contains(@class, "title")]/text()').string()                    if 'weitere' in name2.lower():                        name2 = ''                    if name2 not in XCAT:                        url = cat2.xpath('div[contains(@class, "nav-item--category")]/a/@href | div[contains(@class, "nav-item--and-text")]/div/a[contains(@class, "title")]/@href').string()                        session.queue(Request(url), process_prodlist, dict(cat=name+'|'+name1+'|'+name2))# def process_category(data, context, session):#     strip_namespace(data)##     subcats = data.xpath('//div[contains(@x-data, "Kategorie") or contains(@x-data, "Produktkategorie")]//ol/li/a[@href]')#     if not subcats:#         process_prodlist(data, context, session)#         return##     for subcat in subcats:#         name = subcat.xpath('span[contains(@class, "font")]/text()').string()#         url = subcat.xpath('@href').string()#         session.queue(Request(url, max_age=0), process_category, dict(cat=context['cat']+'|'+name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[contains(@class, "product-info ")]')    for prod in prods:        name = prod.xpath('.//a[contains(@class, "product-item-link")]/span/text()').string(multiple=True).strip()        url = prod.xpath('.//a[contains(@class, "product-item-link")]/@href').string()        rating = prod.xpath('.//div[contains(@class, "rating-number")]/span/text()').string()        if rating and float(rating) > 0:            session.queue(Request(url, max_age=0), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url, max_age=0), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    if context['url'] in DUPE_PRODS:        return    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat'].replace('||', '').strip('|')    product.manufacturer = data.xpath('//div[@itemprop="brand"]/meta/@content').string()    product.ssid = data.xpath('//input[@name="product"]/@value').string()    product.sku = data.xpath('//meta[@itemprop="sku"]/@content').string()    ean = data.xpath('//section/@data-loadbee-gtin').string()    if ean:        product.add_property(type='id.ean', value=ean)    mpn = data.xpath('//meta[@itemprop="mpn"]/@content').string()    if mpn:        product.add_property(type='id.manufacturer', value=mpn)    revs = data.xpath('//div[@itemprop="review"]')    for rev in revs:        review = Review()        review.type = 'user'        review.url = product.url        review.title = rev.xpath('div[@itemprop="name"]/text()').string()        review.date = rev.xpath('.//time[@itemprop="datePublished"]/@datetime').string()        author = rev.xpath('.//strong[@itemprop="author"]/span/text()').string()        if author:            review.authors.append(Person(name=author, ssid=author))        grade_overall = rev.xpath('.//meta[@itemprop="ratingValue"]/@content').string()        if grade_overall:            review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))        excerpt = rev.xpath('div[@itemprop="description"]//text()').string(multiple=True)        if excerpt:            excerpt = excerpt.strip(' ,+*')            if excerpt:                review.add_property(type='excerpt', value=excerpt)                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)    if product.reviews:        session.emit(product)        prod_variants = data.xpath('//div[contains(@class, "grouped-product")]/a/@href').strings()        if prod_variants and len(prod_variants) > 0:            DUPE_PRODS.extend(prod_variants)    # Loaded all revs